(1, '2026-03-03 13:02:10', 'Hendro', 'Veronika Waleng Tenawahang', 85.00, '[{\"paragraf_ke\": 1, \"skor_ai\": \"90%\", \"alasan\": \"Paragraf ini memberikan latar belakang yang kuat mengenai pentingnya pendidikan inklusif di Indonesia, mengacu pada undang-undang dan kebijakan yang relevan. Penjelasan tentang hak anak berkebutuhan khusus dan tantangan yang dihadapi dalam pendidikan inklusif sangat jelas dan mendalam.\"}, {\"paragraf_ke\": 2, \"skor_ai\": \"80%\", \"alasan\": \"Paragraf ini menjelaskan tantangan implementasi pendidikan inklusif di daerah dengan akses terbatas. Meskipun informatif, beberapa kalimat terasa panjang dan bisa disederhanakan untuk meningkatkan pemahaman.\"}, {\"paragraf_ke\": 3, \"skor_ai\": \"85%\", \"alasan\": \"Paragraf ini membahas peran lembaga non-pemerintah dalam pendidikan inklusif dengan baik. Namun, ada beberapa istilah yang mungkin perlu dijelaskan lebih lanjut untuk pembaca yang tidak familiar.\"}, {\"paragraf_ke\": 4, \"skor_ai\": \"75%\", \"alasan\": \"Paragraf ini memberikan contoh konkret tentang Bevak Pintar, tetapi penjelasan tentang sejarah dan perkembangan lembaga ini bisa lebih terstruktur untuk meningkatkan alur cerita.\"}, {\"paragraf_ke\": 5, \"skor_ai\": \"80%\", \"alasan\": \"Paragraf ini menjelaskan tujuan dan visi Bevak Pintar dengan baik. Namun, beberapa informasi bisa disajikan dengan lebih ringkas untuk menjaga fokus pada inti pesan.\"}]', 'PROPOSAL BAB I VERONIKA 26.docx', 'laporan/laporan_Veronika Waleng Tenawahang_1772517730.pdf', '36.85.85.45', 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/145.0.0.0 Safari/537.36', 'Belum Diverifikasi'),
(2, '2026-03-03 13:02:15', 'Hendro', 'Veronika Waleng Tenawahang', 85.00, '[{\"paragraf_ke\": 1, \"skor_ai\": \"90%\", \"alasan\": \"Paragraf ini memberikan latar belakang yang kuat mengenai pentingnya pendidikan inklusif di Indonesia, mengacu pada undang-undang dan prinsip-prinsip hak asasi manusia. Penjelasan tentang pendidikan inklusif dan tantangan yang dihadapi di daerah tertentu sangat relevan dan mendalam.\"}, {\"paragraf_ke\": 2, \"skor_ai\": \"80%\", \"alasan\": \"Paragraf ini menjelaskan tantangan implementasi pendidikan inklusif di daerah dengan akses terbatas. Meskipun informatif, beberapa bagian terasa repetitif dan bisa disederhanakan untuk meningkatkan kejelasan.\"}, {\"paragraf_ke\": 3, \"skor_ai\": \"85%\", \"alasan\": \"Paragraf ini membahas peran lembaga non-pemerintah dalam pendidikan inklusif dengan baik. Namun, ada beberapa istilah yang mungkin perlu dijelaskan lebih lanjut untuk pembaca yang tidak familiar.\"}, {\"paragraf_ke\": 4, \"skor_ai\": \"75%\", \"alasan\": \"Paragraf ini memberikan contoh konkret tentang Bevak Pintar, tetapi penjelasan tentang sejarah dan perkembangan lembaga ini bisa lebih terstruktur untuk meningkatkan pemahaman.\"}, {\"paragraf_ke\": 5, \"skor_ai\": \"80%\", \"alasan\": \"Paragraf ini menjelaskan tujuan dan visi Bevak Pintar dengan baik, tetapi bisa lebih mendalam dalam menjelaskan dampak yang telah dicapai oleh lembaga ini.\"}]', 'PROPOSAL BAB I VERONIKA 26.docx', 'laporan/laporan_Veronika Waleng Tenawahang_1772517735.pdf', '36.85.85.45', 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/145.0.0.0 Safari/537.36', 'Belum Diverifikasi'),
(3, '2026-03-03 13:25:05', 'Hendro', 'Veronika Waleng Tenawahang', 85.00, '[{\"paragraf_ke\": 1, \"skor_ai\": \"90%\", \"alasan\": \"Paragraf ini memberikan latar belakang yang kuat tentang pentingnya pendidikan inklusif dan karakter, serta menyajikan data yang relevan untuk mendukung argumen.\"}, {\"paragraf_ke\": 2, \"skor_ai\": \"80%\", \"alasan\": \"Paragraf ini menjelaskan kebijakan pendidikan inklusif dengan baik, tetapi bisa lebih ringkas untuk meningkatkan kejelasan.\"}, {\"paragraf_ke\": 3, \"skor_ai\": \"85%\", \"alasan\": \"Menjelaskan tantangan dan perkembangan pendidikan inklusif di Indonesia dengan baik, meskipun ada beberapa pengulangan informasi.\"}, {\"paragraf_ke\": 4, \"skor_ai\": \"75%\", \"alasan\": \"Menyajikan data statistik yang relevan, tetapi bisa lebih terstruktur untuk meningkatkan pemahaman.\"}, {\"paragraf_ke\": 5, \"skor_ai\": \"80%\", \"alasan\": \"Menjelaskan inisiatif lokal dengan baik, namun perlu lebih banyak contoh konkret untuk memperkuat argumen.\"}, {\"paragraf_ke\": 6, \"skor_ai\": \"70%\", \"alasan\": \"Menyebutkan kendala dalam pendidikan inklusif, tetapi kurang mendalam dalam analisis penyebab dan solusi.\"}, {\"paragraf_ke\": 7, \"skor_ai\": \"85%\", \"alasan\": \"Menjelaskan keberadaan Bevak Pintar dengan baik, memberikan konteks yang jelas tentang tujuan dan metode.\"}, {\"paragraf_ke\": 8, \"skor_ai\": \"90%\", \"alasan\": \"Paragraf ini sangat kuat dalam menjelaskan nilai-nilai karakter kristiani yang diajarkan di Bevak Pintar.\"}, {\"paragraf_ke\": 9, \"skor_ai\": \"80%\", \"alasan\": \"Menjelaskan tantangan yang dihadapi Bevak Pintar dengan baik, tetapi bisa lebih spesifik dalam menyebutkan solusi yang diusulkan.\"}]', 'BAB I VERONIKA.docx', 'laporan/laporan_Veronika_Waleng_Tenawahang_1772519105.pdf', '36.85.85.45', 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/145.0.0.0 Safari/537.36', 'Belum Diverifikasi'),
(4, '2026-03-03 14:07:33', 'Hendro', 'Veronika Waleng Tenawahang', 75.00, '{\"5\": {\"paragraf_index\": 5, \"skor\": 85, \"kalimat_index\": [1, 2, 3], \"alasan\": \"Paragraf ini mengandung banyak informasi yang kompleks dan berpotensi membingungkan pembaca, terutama terkait dengan kebijakan pendidikan inklusif dan peraturan yang mendasarinya.\"}, \"8\": {\"paragraf_index\": 8, \"skor\": 80, \"kalimat_index\": [1, 2, 3], \"alasan\": \"Paragraf ini mencakup data statistik yang signifikan, tetapi penyampaian informasi yang padat dapat menyebabkan kesulitan dalam pemahaman bagi pembaca yang tidak terbiasa dengan konteks pendidikan inklusif.\"}, \"10\": {\"paragraf_index\": 10, \"skor\": 90, \"kalimat_index\": [1, 2, 3], \"alasan\": \"Paragraf ini menjelaskan kendala dalam implementasi pendidikan inklusif dengan detail yang tinggi, namun dapat membuat pembaca merasa tertekan dengan banyaknya masalah yang dihadapi.\"}, \"40\": {\"paragraf_index\": 5, \"skor\": 85, \"kalimat_index\": [1, 2, 3], \"alasan\": \"Paragraf ini mengandung banyak informasi yang kompleks dan berpotensi membingungkan pembaca, terutama terkait dengan tantangan yang dihadapi dalam implementasi pendidikan inklusif.\"}, \"43\": {\"paragraf_index\": 8, \"skor\": 80, \"kalimat_index\": [1, 2], \"alasan\": \"Paragraf ini menyajikan beberapa masalah yang diidentifikasi, yang dapat menyebabkan kebingungan jika tidak dijelaskan dengan lebih rinci.\"}, \"45\": {\"paragraf_index\": 10, \"skor\": 90, \"kalimat_index\": [1, 2, 3], \"alasan\": \"Paragraf ini mengandung pertanyaan rumusan masalah yang kompleks dan memerlukan pemahaman mendalam tentang konteks pendidikan inklusif.\"}}', 'BAB I VERONIKA.docx', 'laporan/laporan_Veronika_Waleng_Tenawahang_1772521653.pdf', '36.85.85.45', 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/145.0.0.0 Safari/537.36', 'Belum Diverifikasi'),
(5, '2026-03-03 14:28:55', 'Hendro', 'Veronika Waleng Tenawahang', 75.00, '{\"5\": {\"paragraf_index\": 5, \"skor\": 85, \"kalimat_index\": [1, 2, 3], \"alasan\": \"Paragraf ini mengandung banyak informasi yang kompleks dan berpotensi menimbulkan kesalahpahaman jika tidak dipahami dengan baik. Selain itu, penggunaan istilah hukum dan kebijakan pendidikan yang spesifik dapat membingungkan pembaca yang tidak familiar dengan konteks tersebut.\"}, \"8\": {\"paragraf_index\": 8, \"skor\": 80, \"kalimat_index\": [1, 2, 3], \"alasan\": \"Paragraf ini menjelaskan tentang data statistik yang penting namun dapat menimbulkan kebingungan jika tidak disajikan dengan jelas. Penggunaan angka dan persentase yang tinggi dapat membuat pembaca merasa tertekan atau skeptis terhadap informasi yang disampaikan.\"}, \"10\": {\"paragraf_index\": 10, \"skor\": 90, \"kalimat_index\": [1, 2, 3], \"alasan\": \"Paragraf ini mengandung banyak istilah teknis dan referensi yang mungkin tidak dipahami oleh semua pembaca. Hal ini dapat menyebabkan kesulitan dalam memahami inti dari argumen yang disampaikan.\"}, \"12\": {\"paragraf_index\": 12, \"skor\": 85, \"kalimat_index\": [1, 2, 3], \"alasan\": \"Paragraf ini membahas kendala dalam implementasi pendidikan inklusif yang kompleks dan berpotensi menimbulkan kebingungan. Penggunaan istilah yang tidak umum dan penjelasan yang panjang dapat membuat pembaca kehilangan fokus.\"}, \"40\": {\"paragraf_index\": 5, \"skor\": 85, \"kalimat_index\": [1, 2, 3], \"alasan\": \"Paragraf ini mengandung banyak informasi yang kompleks dan berpotensi membingungkan pembaca, terutama terkait dengan tantangan yang dihadapi dalam implementasi pendidikan inklusif.\"}, \"43\": {\"paragraf_index\": 8, \"skor\": 80, \"kalimat_index\": [1, 2], \"alasan\": \"Paragraf ini menyajikan beberapa masalah yang diidentifikasi, yang dapat menyebabkan kebingungan jika tidak dijelaskan dengan lebih rinci.\"}, \"45\": {\"paragraf_index\": 10, \"skor\": 90, \"kalimat_index\": [1, 2, 3], \"alasan\": \"Paragraf ini mengandung pertanyaan rumusan masalah yang kompleks dan memerlukan pemahaman mendalam tentang konteks pendidikan inklusif.\"}}', 'BAB I VERONIKA.docx', 'laporan/laporan_Veronika_Waleng_Tenawahang_1772522935.pdf', '36.85.85.45', 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/145.0.0.0 Safari/537.36', 'Belum Diverifikasi'),
(6, '2026-03-03 14:30:55', 'Hendro', 'Yosefa Sabina Witi', 83.00, '{\"3\": {\"paragraf_index\": 3, \"skor\": 70, \"kalimat_index\": [1, 2, 3], \"alasan\": \"Penggunaan referensi yang tidak jelas dan tidak konsisten dapat menimbulkan keraguan tentang validitas informasi yang disajikan.\"}, \"5\": {\"paragraf_index\": 5, \"skor\": 75, \"kalimat_index\": [1, 2, 3], \"alasan\": \"Pernyataan yang terlalu umum dan tidak didukung oleh data empiris dapat mengurangi kekuatan argumen yang disampaikan.\"}, \"7\": {\"paragraf_index\": 7, \"skor\": 80, \"kalimat_index\": [1, 2], \"alasan\": \"Keterkaitan antara teori dan praktik yang tidak dijelaskan secara mendalam dapat menyebabkan kebingungan bagi pembaca mengenai aplikasi nyata dari konsep yang dibahas.\"}, \"20\": {\"paragraf_index\": 1, \"skor\": 90, \"kalimat_index\": [1, 2, 3, 4], \"alasan\": \"Penggunaan istilah teknis dan referensi yang banyak dapat membuat pemahaman menjadi sulit bagi pembaca yang tidak familiar dengan topik ini.\"}, \"21\": {\"paragraf_index\": 2, \"skor\": 80, \"kalimat_index\": [1, 2, 3, 4], \"alasan\": \"Pernyataan yang kompleks dan panjang dapat menyebabkan kebingungan, terutama dalam menjelaskan interaksi antara faktor internal dan eksternal.\"}, \"22\": {\"paragraf_index\": 3, \"skor\": 75, \"kalimat_index\": [1, 2, 3], \"alasan\": \"Penggunaan istilah akademis yang tinggi dan struktur kalimat yang rumit dapat mengurangi keterbacaan dan pemahaman.\"}, \"23\": {\"paragraf_index\": 4, \"skor\": 85, \"kalimat_index\": [1, 2, 3], \"alasan\": \"Referensi yang banyak dan penjelasan yang mendalam dapat membuat pembaca merasa kewalahan dan kehilangan fokus.\"}, \"24\": {\"paragraf_index\": 5, \"skor\": 70, \"kalimat_index\": [1, 2, 3], \"alasan\": \"Panjang kalimat dan penggunaan jargon akademis dapat menghambat pemahaman bagi pembaca awam.\"}, \"37\": {\"paragraf_index\": 4, \"skor\": 87, \"kalimat_index\": [1, 2, 3, 4, 5], \"alasan\": \"Referensi yang kuat dan analisis yang mendalam dapat menyebabkan kesamaan dengan teks akademik lainnya.\"}, \"39\": {\"paragraf_index\": 6, \"skor\": 89, \"kalimat_index\": [1, 2, 3, 4, 5], \"alasan\": \"Analisis yang mendalam dan penggunaan istilah teknis dapat menimbulkan kesan bahwa teks ini terlalu mirip dengan sumber aslinya.\"}, \"41\": {\"paragraf_index\": 8, \"skor\": 85, \"kalimat_index\": [1, 2, 3, 4, 5], \"alasan\": \"Referensi yang kuat dan analisis yang mendalam dapat menyebabkan kesamaan dengan teks akademik lainnya.\"}, \"34\": {\"paragraf_index\": 1, \"skor\": 90, \"kalimat_index\": [1, 2, 3, 4, 5], \"alasan\": \"Penggunaan referensi yang banyak dan perbandingan metodologis yang mendalam dapat meningkatkan risiko plagiarisme.\"}, \"35\": {\"paragraf_index\": 2, \"skor\": 85, \"kalimat_index\": [1, 2, 3, 4, 5], \"alasan\": \"Analisis yang mendalam dan penggunaan istilah teknis dapat menimbulkan kesan bahwa teks ini terlalu mirip dengan sumber aslinya.\"}, \"36\": {\"paragraf_index\": 3, \"skor\": 88, \"kalimat_index\": [1, 2, 3, 4, 5], \"alasan\": \"Pernyataan yang sangat spesifik dan penggunaan data dari penelitian lain dapat meningkatkan risiko kesamaan dengan karya yang ada.\"}, \"38\": {\"paragraf_index\": 5, \"skor\": 86, \"kalimat_index\": [1, 2, 3, 4, 5], \"alasan\": \"Penggunaan data dan metodologi yang spesifik dapat meningkatkan risiko plagiarisme.\"}, \"40\": {\"paragraf_index\": 7, \"skor\": 90, \"kalimat_index\": [1, 2, 3, 4, 5], \"alasan\": \"Pernyataan yang sangat spesifik dan penggunaan data dari penelitian lain dapat meningkatkan risiko kesamaan dengan karya yang ada.\"}, \"42\": {\"paragraf_index\": 9, \"skor\": 88, \"kalimat_index\": [1, 2, 3, 4, 5], \"alasan\": \"Penggunaan data dan metodologi yang spesifik dapat meningkatkan risiko plagiarisme.\"}, \"43\": {\"paragraf_index\": 10, \"skor\": 87, \"kalimat_index\": [1, 2, 3, 4, 5], \"alasan\": \"Analisis yang mendalam dan penggunaan istilah teknis dapat menimbulkan kesan bahwa teks ini terlalu mirip dengan sumber aslinya.\"}, \"29\": {\"paragraf_index\": 1, \"skor\": 75, \"kalimat_index\": [1, 2, 3], \"alasan\": \"Penggunaan istilah teknis dan teori yang kompleks dapat menyebabkan kesulitan pemahaman bagi pembaca yang tidak familiar dengan konsep-konsep tersebut.\"}, \"30\": {\"paragraf_index\": 2, \"skor\": 80, \"kalimat_index\": [1, 2, 3], \"alasan\": \"Referensi terhadap penelitian terdahulu tanpa penjelasan yang cukup dapat menimbulkan kebingungan mengenai relevansi dan konteks penelitian yang sedang dibahas.\"}, \"31\": {\"paragraf_index\": 3, \"skor\": 70, \"kalimat_index\": [1, 2], \"alasan\": \"Pernyataan tentang kesenjangan penelitian yang tidak dijelaskan secara rinci dapat mengurangi kejelasan dan kekuatan argumen.\"}, \"32\": {\"paragraf_index\": 4, \"skor\": 90, \"kalimat_index\": [1, 2], \"alasan\": \"Pernyataan hipotesis yang terlalu teknis dan panjang dapat menyulitkan pembaca dalam memahami inti dari penelitian.\"}}', 'BAB 2_PROPOSAL_YOSEFA SABINA WITI_2026 FIX PAKE.docx', 'laporan/laporan_Yosefa_Sabina_Witi_1772523055.pdf', '36.85.85.45', 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/145.0.0.0 Safari/537.36', 'Belum Diverifikasi'),
(7, '2026-03-03 14:43:02', 'Hendro', 'Veronika Waleng Tenawahang', 85.00, '{\"3\": {\"paragraf_index\": 3, \"skor\": 75, \"kalimat_index\": [1, 2, 3], \"alasan\": \"Penggunaan referensi yang tidak konsisten dan tidak jelas dapat menimbulkan kebingungan mengenai sumber informasi.\"}, \"5\": {\"paragraf_index\": 5, \"skor\": 70, \"kalimat_index\": [1, 2, 3], \"alasan\": \"Pernyataan yang terlalu umum dan tidak didukung oleh data empiris dapat mengurangi kredibilitas argumen.\"}, \"7\": {\"paragraf_index\": 7, \"skor\": 80, \"kalimat_index\": [1, 2], \"alasan\": \"Pernyataan yang terlalu luas tanpa batasan yang jelas dapat menyebabkan interpretasi yang salah.\"}, \"9\": {\"paragraf_index\": 9, \"skor\": 65, \"kalimat_index\": [1, 2, 3], \"alasan\": \"Keterkaitan antara faktor internal dan eksternal tidak dijelaskan dengan cukup mendalam, berpotensi menimbulkan kesalahpahaman.\"}, \"28\": {\"paragraf_index\": 1, \"skor\": 90, \"kalimat_index\": [1, 2, 3, 4], \"alasan\": \"Penggunaan istilah teknis dan referensi yang banyak dapat membuat pemahaman menjadi sulit bagi pembaca yang tidak familiar dengan topik ini.\"}, \"29\": {\"paragraf_index\": 2, \"skor\": 80, \"kalimat_index\": [1, 2, 3], \"alasan\": \"Pernyataan yang kompleks dan panjang dapat menyebabkan kebingungan dalam memahami hubungan antara faktor-faktor yang dibahas.\"}, \"30\": {\"paragraf_index\": 3, \"skor\": 75, \"kalimat_index\": [1, 2, 3], \"alasan\": \"Penggunaan istilah yang berulang dan struktur kalimat yang rumit dapat mengurangi kejelasan dan membuat pembaca kehilangan fokus.\"}, \"31\": {\"paragraf_index\": 4, \"skor\": 85, \"kalimat_index\": [1, 2, 3], \"alasan\": \"Referensi yang banyak dan penjelasan yang mendalam dapat membuat pembaca merasa kewalahan dan sulit untuk mengikuti alur pemikiran.\"}, \"32\": {\"paragraf_index\": 5, \"skor\": 70, \"kalimat_index\": [1, 2, 3], \"alasan\": \"Penggunaan istilah akademis yang tinggi dan kalimat yang panjang dapat mengurangi aksesibilitas teks bagi pembac